function minimumWindowSubstring(data) {
    const [s, t] = data.split('\n');
    const tCount = {};
    for (let char of t) {
        tCount[char] = (tCount[char] || 0) + 1;
    }
    let minLength = Infinity;
    let minSubstring = "";

    for (let start = 0; start < s.length; start++) {
        for (let end = start + 1; end <= s.length; end++) {
            const substring = s.slice(start, end);
            const substringCount = {};
            for (let char of substring) {
                substringCount[char] = (substringCount[char] || 0) + 1;
            }
            let containsAll = true;
            for (let char in tCount) {
                if (!substringCount[char] || substringCount[char] < tCount[char]) {
                    containsAll = false;
                    break;
                }
            }
            if (containsAll && substring.length < minLength) {
                minLength = substring.length;
                minSubstring = substring;
            }
        }
    }
    return minSubstring;
}

