class Solution {
    public String minimumWindowSubstring(String data) {
        String s = data.split(" ")[0];
        String t = data.split(" ")[1];
        int minLength = Integer.MAX_VALUE;
        String minSubstring = "";
        for (int i = 0; i < s.length(); i++) {
            for (int j = i; j < s.length(); j++) {
                String substring = s.substring(i, j + 1);
                if (containsAllChars(substring, t)) {
                    if (substring.length() < minLength) {
                        minLength = substring.length();
                        minSubstring = substring;
                    }
                }
            }
        }
        return minSubstring;
    }
    private boolean containsAllChars(String substring, String t) {
        int[] charCount = new int[128];
        for (char c : t.toCharArray()) {
            charCount[c]++;
        }
        for (char c : substring.toCharArray()) {
            charCount[c]--;
        }
        for (int count : charCount) {
            if (count > 0) {
                return false;
            }
        }
        return true;
    }
}

